INSERT INTO feedback (source, author, content, urgency, created_at) VALUES

-- Discord: Bug reports (people yelling in #help or #bugs)
('discord', 'dev_sarah#4821', 'yo the new rate limiter is WAY too aggressive. we went from 1000 req/min to hitting 429s at like 200 req/min after the march 5 update. this is breaking our stripe webhook integration and customers are seeing failed payments. anyone else??', NULL, '2026-03-09 14:30:00'),
('discord', 'infra_lead#7702', 'websocket connections dropping every 30 seconds on free tier. confirmed with tcpdump — server sends FIN at exactly 30s. our realtime collab feature is completely dead. paid tier works fine so... is this intentional? its not documented anywhere', NULL, '2026-03-07 22:10:00'),
('discord', 'prod_engineer#8811', 'HELP — our Worker started returning 1042 errors at 3am. no code changes. wrangler status shows healthy but requests failing with "Worker exceeded CPU time limit" even tho our p99 is 8ms which is way under the 50ms limit??? whats going on', NULL, '2026-03-06 03:15:00'),
('discord', 'sre_kim#3399', 'is anyone else seeing stale reads in D1? we INSERT a row then immediately SELECT it and get zero results. adding a 100ms sleep "fixes" it which means theres some internal replication delay even for same-connection reads. this cant be right', NULL, '2026-03-04 11:20:00'),

-- Discord: More bugs
('discord', 'backend_jen#1199', 'CORS errors calling our API from React app. set Access-Control-Allow-Origin to * in Worker response headers but preflight OPTIONS still returns 403. the docs section on CORS is literally 2 paragraphs lol. anyone know what im doing wrong?', NULL, '2026-03-08 09:20:00'),
('discord', 'startup_raj#5543', 'D1 batch inserts silently truncating after 50 rows??? we insert 200 via .batch() but only 47-52 persist each time. NO ERROR THROWN. had to switch to chunks of 25 which 4x our write latency. this feels like a bug right?', NULL, '2026-03-06 16:45:00'),
('discord', 'fullstack_mo#3318', 'Workers AI keeps timing out for prompts over 500 tokens on llama-3.1-8b-instruct. short prompts = 2s fine. anything longer = 524 timeout at 30s. is there an undocumented context window limit or something?', NULL, '2026-03-05 11:00:00'),
('discord', 'veteran_coder#3344', 'wrangler tail disconnects after 2-3 min every single time. tested macos 14.3 and ubuntu 22.04, wrangler 3.60.1. same on both. websocket just closes, no error. how are we supposed to debug prod like this', NULL, '2026-03-04 18:00:00'),
('discord', 'db_admin#5512', 'D1 .prepare().bind() throws "too many SQL variables" at 100+ params in an IN clause. postgres handles 10k+. had to implement manual query chunking which is annoying and slow. any workarounds?', NULL, '2026-03-03 14:30:00'),
('discord', 'api_dev#9934', 'uhh KV .list() with prefix is broken? list({prefix: "user:"}) returns keys like "username:" and "user_settings:" that clearly dont match the prefix. the matching seems to be doing starts-with on each character independently or something weird', NULL, '2026-03-02 16:00:00'),
('discord', 'edge_runner#4401', 'Worker returns "Error 1101: Worker threw exception" in prod but works fine in wrangler dev. error gives ZERO context about which line. added try-catch everywhere and the exception is coming from inside the D1 driver itself. super helpful 🙃', NULL, '2026-03-01 10:45:00'),
('discord', 'performance_pete#6677', 'heads up — Workers AI bge-small-en-v1.5 returns DIFFERENT vector dimensions depending on input length. short strings = 384 dims, strings over 256 chars = 512 dims. this broke our Vectorize index. definitely a bug', NULL, '2026-02-28 09:00:00'),

-- Discord: Feature requests / questions
('discord', 'cloud_mike#8876', 'anyone know if theres a way to export Worker logs as CSV or JSON? we need it for SOX compliance audits. rn we literally screenshot the dashboard lmao. would pay extra for a log export API', NULL, '2026-03-08 16:45:00'),
('discord', 'devops_anna#2201', 'would kill for a native Prometheus /metrics endpoint from Workers. currently we push to Logpush → transform in Datadog. a native metrics binding with req count + latency percentiles would eliminate our entire observability pipeline', NULL, '2026-03-07 10:15:00'),
('discord', 'api_builder#6654', 'can we get webhook support for D1 triggers? like when a row is inserted/updated, fire a webhook. would eliminate the polling pattern that literally 90% of us are doing. SQLite has update_hook — could D1 expose it?', NULL, '2026-03-04 14:30:00'),
('discord', 'realtime_dev#7789', 'please add websocket broadcast support 🙏 broadcasting to 100 clients means looping through each one rn. DOs help but for simple pub-sub its massive overkill. just give us a native broadcast primitive', NULL, '2026-03-03 13:00:00'),
('discord', 'testing_tara#2288', 'need a proper mocking library for D1 in unit tests. currently we run wrangler dev in background and make HTTP calls which is ridiculous. no way to instantiate D1 binding in vitest/jest without full runtime. miniflare helps but setup is painful', NULL, '2026-03-02 11:15:00'),
('discord', 'workflow_builder#5501', 'workflows need a visual debugger BAD. when a workflow fails at step 3 of 7 i cant see the state at each step. have to add console.log everywhere and redeploy. something like AWS Step Functions visual trace would be a game changer', NULL, '2026-03-01 15:30:00'),
('discord', 'schema_guy#1188', 'D1 ALTER TABLE ADD COLUMN when?? adding a column requires creating new table → copy data → drop old → rename. i know its a SQLite thing but D1 should abstract it away with a migration helper', NULL, '2026-02-27 14:00:00'),
('discord', 'multi_region#4456', 'any plans for multi-region D1 write replicas? we have users in US/EU/APAC. reads are fast from replicas but writes all route to US-East = 200ms for APAC users. write-local-read-global would be ideal', NULL, '2026-02-25 08:30:00'),

-- Discord: Positive / Praise
('discord', 'speed_demon#1234', 'just migrated from Lambda to Workers and our cold start went from 800ms to LITERALLY 0ms. p99 dropped 340ms → 12ms. DX is incredible. datadog bill dropped 40%. shoutout to the Workers team you guys cook 🔥', NULL, '2026-03-09 10:15:00'),
('discord', 'indie_maker#9901', 'shipped my entire SaaS on Workers + D1 for $5/mo. 12k active users, 50k daily req, zero scaling issues. this platform literally carried my MVP through YC interviews. free tier is insanely generous', NULL, '2026-03-06 20:00:00'),
('discord', 'new_dev#4455', 'first time using Hono + Workers and i had a full REST API with JWT auth deployed in under 20 min. coming from Express + AWS this is a dream. wrangler dev hot reload feels instant', NULL, '2026-03-03 08:30:00'),
('discord', 'agency_dev#3321', 'deployed 15 client Workers this month. deployment is so reliable we literally removed our staging env lol. wrangler deploy → prod, wrangler rollback if needed. simple and bulletproof', NULL, '2026-02-28 17:00:00'),
('discord', 'ai_builder#7744', 'Workers AI + D1 for our RAG pipeline is *chefs kiss*. embed with bge-small → store in Vectorize → retrieve + generate with llama-3.1. total cost for 10k queries/day is under $3/mo. try doing that on bedrock lmao', NULL, '2026-02-26 12:00:00'),
('discord', 'cost_saver#9988', 'our company saved $4200/mo migrating from Vercel Pro to Workers. same traffic same features but Workers handles it on FREE TIER cuz we were under 100k req/day. the pricing model is just dramatically better', NULL, '2026-02-20 09:30:00'),

-- Discord: UX / Docs complaints
('discord', 'confused_carl#7788', 'ok can someone explain the difference between Workers and Pages because its genuinely unclear. deployed to Pages for my React frontend but couldnt add D1 bindings. turns out i needed Workers with static assets?? nowhere in docs does it say Pages cant do X', NULL, '2026-03-07 13:00:00'),
('discord', 'noob_here#5566', 'tried following the D1 tutorial and step 3 says "add the binding to your wrangler file" but never explains what a binding IS. i googled for 40 minutes before understanding its basically an env variable. docs need a "WTF is a binding" section tbh', NULL, '2026-03-05 09:00:00'),
('discord', 'team_lead_pat#2200', 'our 8 person team cant find the Edit Code button after the dashboard redesign. used to be right on the Worker page. now its Settings > Functions > scroll > Advanced > Edit Code. thats 6 clicks for something we do 20x a day', NULL, '2026-03-02 15:30:00'),
('discord', 'type_confused#6633', 'wrangler types generates types that dont match the runtime API?? generates Env with KVNamespace but runtime methods have different signatures. spent an hour fixing type errors that arent real errors. is this a known issue?', NULL, '2026-03-01 12:00:00'),
('discord', 'migration_pain#8855', 'migrating from Vercel Edge Functions. concepts map 1:1 but syntax is totally different. env.DB vs process.env.DATABASE_URL, c.req vs request. no migration guide anywhere. would save people like me days of pain', NULL, '2026-02-27 16:30:00'),
('discord', 'config_confused#4422', 'is it wrangler.toml or wrangler.jsonc?? docs use both interchangeably. some examples show TOML some show JSON. tried wrangler.jsonc and the AI binding syntax was different from the TOML version. please just pick one', NULL, '2026-02-25 10:00:00'),
('discord', 'error_frustrated#1177', 'got "Error 10021: Could not route to your Worker" after deploying. googled it — not in docs, not in error code reference, not anywhere official. turned out my route pattern was wrong but the error gave ZERO clue. cool', NULL, '2026-02-22 14:30:00'),
('discord', 'dashboard_slow#9944', 'Workers dashboard takes 8-10 SECONDS to load when you have 25+ workers. no loading indicator, just white screen. i keep refreshing thinking its broken. pagination or lazy loading plz', NULL, '2026-02-20 11:00:00'),

-- Discord: Pricing
('discord', 'budget_dev#3366', 'can someone explain Workers AI pricing to me. what even is a "neuron"? why not charge per token like literally every other AI provider? i have no way to estimate my monthly bill because i cant convert tokens to neurons', NULL, '2026-03-04 09:00:00'),
('discord', 'indie_budget#7711', 'free tier is amazing but the jump to $5/mo is steep for my weekend project thats doing 150k req/day. a $1-2 hobby tier at 500k would be perfect. id happily pay $2 but $5 feels like a lot for a blog API', NULL, '2026-02-24 06:30:00');


-- ═══════════════════════════════════════════
--  GITHUB ISSUES (42 entries)
-- ═══════════════════════════════════════════

INSERT INTO feedback (source, author, content, urgency, created_at) VALUES

-- GitHub: Critical bugs
('github', 'user/data_diana', '[BUG] D1 returns inconsistent results with batch queries over 50 statements. Tested: INSERT 100 rows via .batch(), only 47-52 persist per run. Reproducible on wrangler 3.60.1. Steps: 1) create table 2) batch insert 100 rows 3) SELECT COUNT(*). Expected: 100. Actual: varies 47-52.', 'critical', '2026-03-08 08:00:00'),
('github', 'user/ci_pipeline', '[BUG] wrangler deploy hangs indefinitely in GitHub Actions with Node 20.11.0. No timeout, no error, process hangs at "Uploading..." forever. Same code deploys fine locally with Node 20.11.0 and in CI with Node 18.19.0. Env: ubuntu-latest, wrangler 3.60.1.', 'critical', '2026-03-06 07:00:00'),
('github', 'user/prod_down', '[BUG] Workers returning 1042 "Worker exceeded CPU time limit" intermittently since March 5 with no code changes. Affected Workers use D1 with simple SELECT queries. CPU time reported in dashboard is 3-8ms well under 50ms limit. Suspect D1 cold start is counted against CPU time.', 'critical', '2026-03-05 04:00:00'),
('github', 'user/data_loss', '[BUG] D1 DROP TABLE followed by CREATE TABLE in same migration file causes silent data loss in production. The migration succeeds but queries against the new table return schema errors until Worker is redeployed. Workaround: separate into two migration files.', 'critical', '2026-03-02 06:30:00'),

-- GitHub: High-urgency bugs
('github', 'user/octodev', '[BUG] Worker deployment fails silently when wrangler.toml has trailing whitespace in binding names. Example: binding = "DB " (note space). No error message, exits code 0, but Worker cannot access the binding at runtime. Should validate binding names at deploy time.', 'high', '2026-03-09 11:00:00'),
('github', 'user/edge_dev', '[BUG] KV .get() returns null for keys just written via .put() within the same request. Expected: read-your-writes consistency within a single Worker invocation. Actual: .put() then .get() returns null. Workaround: cache writes in a Map and check before .get().', 'high', '2026-03-07 15:30:00'),
('github', 'user/perf_tester', '[BUG] Workers AI llama-3.1-8b-instruct returns different results for identical prompts with temperature=0. Sent same prompt 10 times, got 7 unique responses. Expected: deterministic output at temp=0. This makes testing impossible.', 'high', '2026-03-04 12:00:00'),
('github', 'user/error_reporter', '[BUG] wrangler d1 execute returns "SQLITE_ERROR" with no line number when SQL has a syntax error. In a 200-line migration file this means binary-search debugging. PostgreSQL shows exact line and position. D1 should at minimum show the failing statement.', 'high', '2026-03-01 16:30:00'),
('github', 'user/memory_leak', '[BUG] Workers using fetch() to call external APIs leak memory when the response body is not consumed. After ~500 requests the Worker starts returning 1102 errors. Adding response.text() or response.arrayBuffer() after every fetch prevents this.', 'high', '2026-02-28 13:00:00'),
('github', 'user/r2_issue', '[BUG] R2 .put() with custom metadata containing unicode characters silently strips the metadata. No error thrown. Key is stored but metadata is empty. Workaround: base64 encode metadata values. Tested with Chinese and Arabic characters.', 'high', '2026-02-26 09:30:00'),
('github', 'user/kv_race', '[BUG] KV .put() followed by .delete() in rapid succession sometimes results in the key still existing. Suspect eventual consistency race condition. This causes duplicate processing in our idempotency check. Need atomic delete-if-exists.', 'high', '2026-02-24 15:00:00'),
('github', 'user/wrangler_crash', '[BUG] wrangler dev crashes with SIGTERM when project has more than 500 TypeScript files. Stack trace points to esbuild bundler running out of file descriptors. Workaround: increase ulimit -n to 8192. Should be documented or handled gracefully.', 'high', '2026-02-22 11:00:00'),
('github', 'user/timeout_bug', '[BUG] Scheduled (cron) Workers silently skip execution if the previous run has not completed. No log entry, no error, the cron just does not fire. With a 1-minute cron and a 90-second execution time, every other run is skipped silently.', 'high', '2026-02-18 08:00:00'),

-- GitHub: Feature requests
('github', 'user/serverless_sam', '[FEATURE] Scheduled cron triggers with sub-minute granularity. Current minimum is 1 minute. For health checks and heartbeat monitoring we need 15-second intervals. Workaround is a Durable Object alarm which is overkill for simple cron.', 'medium', '2026-03-08 14:30:00'),
('github', 'user/ml_ops', '[FEATURE] Workers AI streaming responses for text generation. Currently env.AI.run() returns the complete response, adding 3-5s latency for longer outputs. Support for ReadableStream response would enable SSE to frontend for ChatGPT-like UX.', 'high', '2026-03-07 12:00:00'),
('github', 'user/data_eng', '[FEATURE] D1 RETURNING clause for INSERT/UPDATE/DELETE. Current workaround: INSERT then SELECT last_insert_rowid(). This is two queries instead of one. SQLite 3.35+ supports RETURNING natively. D1 should expose it.', 'medium', '2026-03-05 16:00:00'),
('github', 'user/security_first', '[FEATURE] Row-level security for D1. In multi-tenant apps every query must include WHERE tenant_id = ?. A database-level policy like PostgreSQL RLS would prevent accidental data leaks. This is a common enterprise requirement blocking D1 adoption.', 'high', '2026-03-03 09:00:00'),
('github', 'user/dx_advocate', '[FEATURE] Hot module replacement for wrangler dev. Every code save triggers a 3-4 second full restart. With HMR only changed modules reload, keeping the dev feedback loop under 500ms. Vite has proven this pattern works.', 'medium', '2026-03-01 14:00:00'),
('github', 'user/queue_builder', '[FEATURE] Dead letter queue for Workers Queue. When a message fails processing 3 times it disappears. Need a DLQ to capture failed messages for debugging. AWS SQS has had this for 15 years.', 'medium', '2026-02-27 10:00:00'),
('github', 'user/observability', '[FEATURE] Structured logging API. console.log() works but there is no way to add log levels, structured fields, or trace IDs. A native logger with JSON output and correlation IDs would replace the custom logging wrappers everyone builds.', 'medium', '2026-02-25 14:00:00'),
('github', 'user/auth_dev', '[FEATURE] Built-in JWT validation middleware for Workers. Nearly every API Worker needs JWT auth. Currently everyone copies the same 40 lines of JWT verification code. A native binding like env.JWT.verify(token, secret) would standardize this.', 'medium', '2026-02-23 09:00:00'),
('github', 'user/graphql_fan', '[FEATURE] Native GraphQL support or at least a GraphQL playground in the dashboard. Workers are commonly used as GraphQL servers. Being able to test queries directly in the CF dashboard without Postman would improve DX significantly.', 'medium', '2026-02-21 16:00:00'),
('github', 'user/env_mgmt', '[FEATURE] Environment variable groups or profiles. We have 15 env vars that differ between staging and production. Managing them individually via wrangler secret put is error-prone. Need wrangler secret import from a .env file.', 'medium', '2026-02-19 11:30:00'),
('github', 'user/rollback_fan', '[FEATURE] One-click rollback to previous deployment with traffic shifting. Currently wrangler rollback exists but there is no gradual rollback with percentage-based traffic splitting. If a deploy is bad we want to shift 10% back then 50% then 100%.', 'medium', '2026-02-17 08:00:00'),
('github', 'user/cost_tracker', '[FEATURE] Per-Worker cost breakdown in the dashboard. We have 30 Workers and the billing page shows one aggregate number. No way to know which Worker is consuming the most resources without building custom analytics.', 'medium', '2026-02-15 13:00:00'),

-- GitHub: Docs issues
('github', 'user/doc_hunter', '[DOCS] KV list() documentation missing examples for cursor-based pagination and prefix filtering. The return type is documented but no code example shows how to paginate through 10000+ keys. Had to reverse-engineer from community Discord posts.', 'medium', '2026-03-07 17:30:00'),
('github', 'user/first_timer', '[DOCS] Workers AI Getting Started references deprecated @cloudflare/ai package instead of native env.AI binding. The old package still installs but throws cryptic errors at runtime. Wasted 30 minutes before finding the correct approach in a blog post.', 'high', '2026-03-06 10:00:00'),
('github', 'user/migration_pro', '[DOCS] No migration guide from KV to D1. Many projects start with KV for simplicity then need relational queries. Need a guide covering: data export from KV, schema design for D1, migration script patterns, and performance comparison.', 'medium', '2026-03-04 08:30:00'),
('github', 'user/type_nerd', '[DOCS] D1 .all() returns D1Result<Record<string, unknown>>. No documentation on how to properly type results. The generic parameter is documented in TypeScript source but not on the website. Example: .all<{id: number, name: string}>() works but is not shown.', 'medium', '2026-03-02 11:00:00'),
('github', 'user/websocket_dev', '[DOCS] WebSocket documentation does not cover hibernation API at all. The hibernation pattern is mentioned in a blog post from 2024 but the official docs still show the old non-hibernating pattern which uses 10x more CPU.', 'medium', '2026-02-28 16:00:00'),
('github', 'user/durable_confused', '[DOCS] Durable Objects pricing page says "based on duration" but does not explain what "duration" means. Is it wall-clock time the DO exists? Time it is actively processing? Time between first and last request? Three different interpretations lead to 100x cost difference.', 'medium', '2026-02-26 10:00:00'),
('github', 'user/binding_newbie', '[DOCS] The bindings concept needs a dedicated explainer page. Currently bindings are mentioned everywhere but defined nowhere. A "What are Bindings?" page with diagrams showing the relationship between Worker code, wrangler.toml, and runtime env would help all beginners.', 'medium', '2026-02-24 08:00:00'),
('github', 'user/rate_limit_docs', '[DOCS] Rate limiting documentation only covers the Cloudflare WAF rate limiter. No docs on implementing rate limiting INSIDE a Worker using KV or Durable Objects. This is one of the most common Worker patterns and has zero official guidance.', 'medium', '2026-02-22 14:00:00'),
('github', 'user/testing_docs', '[DOCS] No official guide for unit testing Workers. The community has vitest-pool-workers but it is not mentioned in official docs. A "Testing Your Worker" guide covering unit tests, integration tests with miniflare, and CI setup would be extremely valuable.', 'medium', '2026-02-20 09:30:00'),
('github', 'user/changelog_gap', '[DOCS] D1 changelog does not document breaking changes. The batch() method behavior changed to limit at 50 statements but this was not in any changelog or migration guide. We discovered it in production.', 'high', '2026-02-16 07:00:00');


-- ═══════════════════════════════════════════
--  SUPPORT TICKETS (42 entries)
-- ═══════════════════════════════════════════

INSERT INTO feedback (source, author, content, urgency, created_at) VALUES

-- Support: Critical enterprise blockers
('support', 'Acme Corp (Enterprise)', 'Our team of 50 developers cannot access the Workers dashboard since yesterday. All receive 403 Forbidden. We verified our SSO config is correct. Account ID: acme-12345. We are blocked on a critical Q1 deployment. Every hour of delay directly impacts revenue.', 'critical', '2026-03-09 08:00:00'),
('support', 'FinSecure Inc (Enterprise)', 'We need SOC2 Type II compliance documentation specifically for Workers AI. Where is inference data processed geographically? Is any data retained after inference? Is data used for model training? Our $2M banking contract depends on this documentation within 2 weeks.', 'critical', '2026-03-08 07:00:00'),
('support', 'GlobalBank AG (Enterprise)', 'D1 database became unresponsive at 2:47 AM UTC. All queries return 500 errors. We have 200K active users on this database. The dashboard shows the database as "healthy" but no queries execute. This is our primary transaction ledger.', 'critical', '2026-03-06 02:47:00'),
('support', 'PayFlow Systems (Enterprise)', 'Our Workers processing payment webhooks started returning 1015 errors after deploying a new version at 11pm. We rolled back but errors continue. The old version SHA matches what was running before. We are manually processing payments and losing $50K/hour.', 'critical', '2026-03-03 23:15:00'),
('support', 'CloudVault Security (Enterprise)', 'mTLS certificate rotation on Workers caused a 12-minute outage. The new cert was uploaded and bound correctly but there was a gap between old cert expiry and new cert propagation. Need atomic cert rotation or at least overlap support.', 'critical', '2026-02-25 16:00:00'),

-- Support: High urgency issues
('support', 'MegaRetail Inc (Business)', 'Need per-route rate limits instead of global. Our checkout API handles 5000 req/min during flash sales but catalog browsing needs only 500 req/min. A single global limit either over-provisions checkout or throttles browsing. Need route-level granularity.', 'high', '2026-03-07 10:30:00'),
('support', 'EduTech Solutions (Business)', 'Stuck on DNS configuration for 2 days. The dashboard shows "invalid configuration" with no details. Is it the record type? TTL value? CNAME format? We tried 15 combinations. Support article KB-2847 does not cover our edge case of subdomain delegation.', 'high', '2026-03-06 11:00:00'),
('support', 'LogiChain (Enterprise)', 'We require data residency guarantees for EU customers under GDPR Article 46. Can Workers execution and D1 storage be pinned to EU-only regions? The "location hint" in D1 is insufficient for compliance because hint does not mean guarantee. We need contractual SLA.', 'high', '2026-03-05 09:00:00'),
('support', 'HealthApp Pro (Business)', 'Workers AI ResNet image classification returns wrong labels for rotated images. Tested 500 photos: accuracy is 94% for upright images but drops to 61% for 90-degree rotated images. A cat rotated 90 degrees is classified as a bookshelf. This blocks our photo feature launch.', 'high', '2026-03-04 16:00:00'),
('support', 'MediaStream Corp (Business)', 'We need WebSocket support for 10K concurrent connections per Worker. Current limit is 256. Our live streaming chat feature cannot scale. AWS API Gateway WebSocket supports 500K concurrent. Can we get a limit increase or is there an architectural alternative?', 'high', '2026-03-03 14:00:00'),
('support', 'FastShip Logistics (Business)', 'Our Cron Trigger Worker stopped executing on March 1st with no notification. The dashboard still shows it as "Active" but the cron has not fired in 8 days. Our daily inventory sync has been silently broken for over a week.', 'high', '2026-03-09 06:00:00'),
('support', 'NeoCommerce (Business)', 'After upgrading from Workers free to paid plan our Worker started hitting the 128MB memory limit. On free tier the same Worker used 40MB. The upgrade seems to have changed the runtime behavior. Our code is identical.', 'high', '2026-03-07 14:00:00'),
('support', 'DataSync.io (Business)', 'R2 multipart upload of a 4.7GB file fails at 87% completion with "EntityTooLarge" error. The docs say R2 supports up to 5TB per object. The multipart part size is set to 100MB. No clear error about what limit was hit.', 'high', '2026-03-04 08:00:00'),
('support', 'APIFirst Inc (Business)', 'Workers Custom Domains setup requires adding the domain to Cloudflare DNS first. Our domain is on Route53 and we only want to point a subdomain. The docs imply this works with CNAME but the actual setup requires full DNS migration which is a dealbreaker.', 'high', '2026-03-01 10:00:00'),
('support', 'SecureAPI.dev (Business)', 'Workers behind Cloudflare Access return 1020 errors intermittently for authenticated users. The Access JWT is valid and most requests succeed but about 2% fail with 1020. No pattern in timing or user. Retry immediately succeeds.', 'high', '2026-02-27 13:00:00'),

-- Support: Medium urgency
('support', 'DataFlow Analytics (Business)', 'R2 presigned URLs expire silently with no notification webhook or event. Our customers click download links that return 403 with no user-friendly message. Need either: longer max expiry, expiration webhook, or custom error page for expired URLs.', 'medium', '2026-03-05 15:00:00'),
('support', 'TinyStartup LLC', 'The pricing page is genuinely confusing. Workers Paid plan page, Workers AI pricing page, and KV pricing page are three separate pages with different billing models. I cannot calculate my total monthly cost without a spreadsheet. Need a unified pricing calculator.', 'medium', '2026-03-07 13:00:00'),
('support', 'GreenEnergy IoT (Business)', 'IoT devices send telemetry every 5 seconds. We need batch ingestion into D1 without hitting row write limits. Workers Queue could help but the docs do not show a pattern for Queue to D1 batch writes. Need an official batch ingestion pattern.', 'medium', '2026-03-02 10:00:00'),
('support', 'DevAgency.co (Business)', 'Managing 30+ Workers under one account is impossible. No folders, no tags, no search, no grouping. The dashboard lists them alphabetically with no filtering. Need project-level organization like AWS has with resource groups.', 'medium', '2026-02-28 12:00:00'),
('support', 'AnalyticsPro (Business)', 'Workers Analytics Engine has a 25-column limit per dataset. Our event tracking schema has 32 fields. We have to split across two datasets and join client-side which defeats the purpose. Can the column limit be increased to at least 50?', 'medium', '2026-02-26 11:00:00'),
('support', 'TranslateHub (Business)', 'Workers AI translation model m2m100-1.2B does not support Hindi to English translation despite Hindi being listed as a supported language. Returns empty string for hi-to-en but works for en-to-hi. Suspect a model configuration issue.', 'medium', '2026-02-24 09:30:00'),
('support', 'SmartHome.io (Business)', 'Need long-running Worker support beyond 30 seconds for CPU-intensive tasks. Our image processing pipeline takes 45 seconds. Durable Objects help but add complexity for what should be a simple long-running function. AWS Lambda supports 15 minutes.', 'medium', '2026-02-22 15:00:00'),
('support', 'CodeSchool (Business)', 'We run coding workshops and 40 students deploying Workers simultaneously causes rate limiting on wrangler deploy. Getting 429 errors across the class. Need higher deploy rate limits for education accounts or a bulk deploy mechanism.', 'medium', '2026-02-20 10:00:00'),

-- Support: Low urgency / pricing
('support', 'SoloFounder.dev', 'The free-to-paid jump is too steep. Free tier gives 100K req/day. Next is $5/month for 10M/month. My side project needs 300K req/day which is 9M/month. A $2 hobby tier with 1M/month would capture every indie dev building on Workers.', 'low', '2026-03-06 06:00:00'),
('support', 'StudentDev (Individual)', 'The Cloudflare for Students page does not mention Workers AI at all. I signed up for the student plan to use AI features but Workers AI usage is still billed separately. The student page should clearly state what is and is not included.', 'low', '2026-03-04 07:00:00'),
('support', 'FreelancerJoe (Individual)', 'I love Workers but cannot recommend it to clients because there is no SLA for the paid plan. Enterprise has 100% SLA but the $5 paid plan has no uptime commitment at all. Even a 99.9% SLA would give me confidence to propose Workers to clients.', 'low', '2026-03-01 16:00:00'),
('support', 'HobbyDev123 (Individual)', 'The billing dashboard shows usage in "requests" but the Workers AI section shows "neurons". These are different units with different pricing. Would be clearer if everything was normalized to requests and tokens like the rest of the industry.', 'low', '2026-02-27 08:00:00'),

-- Support: Onboarding feedback
('support', 'NewTeam.io (Business)', 'First-time setup for our team of 5. The onboarding flow does not mention creating an API token for CI/CD. We only discovered this after trying to deploy from GitHub Actions and getting auth errors. A "Set up CI/CD" step in onboarding would help.', 'medium', '2026-03-08 09:30:00'),
('support', 'MigrateNow (Business)', 'Migrating from Netlify Functions. The conceptual mapping is unclear: what is the Workers equivalent of Netlify environment variables, build plugins, and edge functions? A Netlify-to-Cloudflare migration guide would have saved us a week.', 'medium', '2026-03-05 11:30:00'),
('support', 'QuickStart Corp (Business)', 'The create-cloudflare CLI asked 8 questions during setup. We just wanted a basic API Worker. Having a "quick start" flag like npm create cloudflare@latest -- --template api --yes would skip all prompts and give us a working API template.', 'medium', '2026-03-02 14:00:00'),
('support', 'TeamOnboard (Business)', 'No way to invite team members with granular permissions for Workers. It is all-or-nothing account access. We need a developer to deploy Workers but not access billing or DNS. Role-based access control at the product level is essential for teams.', 'medium', '2026-02-23 10:00:00');


-- ═══════════════════════════════════════════
--  TWITTER / X (42 entries)
--  (no urgency field — tweets don't have priority levels)
-- ═══════════════════════════════════════════

INSERT INTO feedback (source, author, content, urgency, created_at) VALUES

-- Twitter: Positive
('twitter', '@dev_thoughts', 'just migrated from AWS Lambda to @CloudflareDev Workers and holy shit. p99 went from 340ms to 12ms. cold start is literally 0ms. datadog bill dropped 40%. edge computing is the real deal #serverless #cloudflare', NULL, '2026-03-09 15:00:00'),
('twitter', '@happy_builder', 'shipped my entire saas on @CloudflareDev Workers + D1 + KV. $5/mo. 50k MAU. zero scaling incidents in 6 months. best infra decision we ever made tbh', NULL, '2026-03-07 20:00:00'),
('twitter', '@frontend_fan', 'Hono + @CloudflareDev Workers is incredible. full REST API w/ JWT auth deployed in 45 min. coming from Express + AWS this feels like magic ngl 🔥', NULL, '2026-03-05 12:30:00'),
('twitter', '@startup_ceo', 'Evaluated Lambda, GCP Cloud Functions, Vercel Edge, @CloudflareDev for our Series A. CF won on DX, cold starts, latency, pricing, and the D1 + Workers AI combo. not even close', NULL, '2026-03-03 16:00:00'),
('twitter', '@cost_optimizer', '🧵 how we cut our serverless bill from $847/mo on Vercel to $5/mo on @CloudflareDev Workers. zero perf degradation. same traffic same features. 10-100x cheaper for API workloads. 1/', NULL, '2026-03-01 14:00:00'),
('twitter', '@edge_enthusiast', 'deployed a @CloudflareDev Worker in Tokyo, tested from Mumbai. 23ms. same query on Lambda ap-northeast-1 from Mumbai? 180ms. edge wins and its not close', NULL, '2026-02-27 11:00:00'),
('twitter', '@open_source_dev', 'just dropped my open-source auth library for @CloudflareDev Workers — JWT + OAuth2 + sessions on D1/KV. 500 stars first week 🚀 ecosystem is growing fast #opensource', NULL, '2026-02-25 09:00:00'),
('twitter', '@devrel_speaker', 'gave a talk on @CloudflareDev Workers at ReactConf. live demo deploying full-stack app in 90 seconds got actual gasps lol. no other platform comes close to that deploy speed', NULL, '2026-02-22 18:00:00'),
('twitter', '@migration_success', 'heroku → @CloudflareDev Workers + D1. $250/mo → $5/mo. response times improved 8x. hardest part was accepting you dont need a server anymore lmao', NULL, '2026-02-18 15:00:00'),

-- Twitter: Negative complaints
('twitter', '@frustrated_coder', 'day 3 trying to get @CloudflareDev Workers + D1 + KV working together. the docs assume you know what "bindings" are??? every example is an isolated snippet. zero full project examples. not beginner friendly AT ALL', NULL, '2026-03-09 09:00:00'),
('twitter', '@saas_founder', '@CloudflareDev pls fix wrangler tail. disconnects after 2-3 min EVERY time. reported 6+ months ago. basic observability shouldnt be this broken. we literally cannot debug prod 😤', NULL, '2026-03-08 18:00:00'),
('twitter', '@tech_reviewer', 'published my edge compute comparison. @CloudflareDev Workers: best free tier, fastest cold starts, WORST error messages. "Error 10021" with zero explanation?? its 2026 cmon', NULL, '2026-03-06 14:00:00'),
('twitter', '@mobile_dev', '@CloudflareDev Workers AI — zero docs on streaming responses to mobile clients?? every example is server-side batch. we NEED SSE or websocket streaming for chat UIs. this is table stakes in 2026', NULL, '2026-03-05 10:00:00'),
('twitter', '@agency_lead', 'the @CloudflareDev dashboard takes 8-10 SECONDS to load with 25+ workers. no search no filter no grouping. managing a client portfolio on this feels like 2010 software fr', NULL, '2026-03-04 11:30:00'),
('twitter', '@data_privacy', '@CloudflareDev where tf is the GDPR DPA for Workers AI? our EU legal team wont let us deploy AI inference without it. cant find it anywhere — trust center, docs, legal pages. blocking our entire EU launch', NULL, '2026-03-03 08:00:00'),
('twitter', '@dev_advocate', 'hot take: @CloudflareDev has the best serverless runtime but the most confusing product naming ever. Workers vs Pages vs Functions vs Durable Objects vs Service Bindings vs Workflows. need a product selection wizard yesterday', NULL, '2026-03-01 19:00:00'),
('twitter', '@weekend_hacker', 'first time trying @CloudflareDev Workers. CLI was smooth. then tried adding D1 and immediately lost. whats a binding? whats database_id? where do i find it?? docs assume way too much prior knowledge smh', NULL, '2026-02-27 14:00:00'),
('twitter', '@infra_engineer', 'wrangler deploy took 45 SECONDS today @CloudflareDev. normally 5s. no code change. upload endpoint was just slow ig. at least show a progress bar instead of a spinning cursor??', NULL, '2026-02-25 16:00:00'),
('twitter', '@security_researcher', '@CloudflareDev Workers doesnt support CSP headers natively. have to set it manually in every response. a default header config in wrangler.toml would prevent so many security misconfigs', NULL, '2026-02-23 10:30:00'),
('twitter', '@testing_advocate', 'the fact that @CloudflareDev has ZERO official docs on testing Workers is wild. no test framework rec. no mocks. no CI examples. community built vitest-pool-workers but CF should own this #DX', NULL, '2026-02-21 12:00:00'),
('twitter', '@perf_obsessed', '@CloudflareDev D1 perf degrades hard after 100k rows. SELECT by PK goes 2ms → 45ms. docs only show tiny dataset examples. where is the production-scale perf tuning guide??', NULL, '2026-02-19 08:00:00'),
('twitter', '@api_designer', 'got "Error 1042" from @CloudflareDev Workers. no stack trace. no context. error code isnt even in the docs lol. had to search discord for 30 min to figure out it means CPU time exceeded. cool cool cool', NULL, '2026-02-17 14:00:00'),
('twitter', '@backend_queen', 'love @CloudflareDev Workers but 128MB memory limit is killing us. parsing a 20MB JSON payload OOMs because V8 overhead triples the size. need 256MB option at minimum 🙏', NULL, '2026-02-15 11:00:00'),
('twitter', '@deploy_daily', 'wrangler deploy doesnt show which bindings changed between versions @CloudflareDev. we deploy 10x/day. a simple diff like "D1: unchanged, KV: added namespace" would save us so much grief', NULL, '2026-02-13 09:00:00'),

-- Twitter: Mixed / Neutral observations
('twitter', '@cloud_analyst', 'interesting architectural choice: @CloudflareDev D1 uses SQLite under the hood but doesnt expose all features. ATTACH DATABASE, WAL mode, extensions all missing. simplicity vs power tradeoff i guess', NULL, '2026-03-06 17:00:00'),
('twitter', '@serverless_podcast', 'interviewed @CloudflareDev Workers team for our pod. key takeaway: 30s exec limit is intentional — longer stuff should use Workflows. makes sense but the migration path from Lambda 15min functions is 🤷‍♂️', NULL, '2026-03-02 20:00:00'),
('twitter', '@benchmarker', 'benchmarks: @CloudflareDev Workers AI llama-3.1-8b = 800ms-2.5s depending on region. slower than dedicated GPU obv but zero-ops is worth the tradeoff for most cases imo', NULL, '2026-02-28 13:00:00'),
('twitter', '@dx_researcher', 'studying dev onboarding flows. @CloudflareDev = fastest time-to-first-deploy (<5min) but highest drop-off at bindings config step. the abstraction gap between CLI scaffolding and binding setup is where ppl bail', NULL, '2026-02-24 10:00:00'),
('twitter', '@platform_switcher', 'tried switching from @vercel to @CloudflareDev. DX is different not worse. but the mental model shift from file-system routing to explicit route handlers tripped me up for a whole day. migration guide would help SO much', NULL, '2026-02-20 16:00:00'),
('twitter', '@ai_builder_xyz', '@CloudflareDev Workers AI model catalog growing fast but still no speech-to-text for non-English. need Whisper w/ Hindi + Spanish for our CS bot. using OpenAI API instead which defeats the purpose lol', NULL, '2026-02-16 14:00:00');


-- ═══════════════════════════════════════════
--  EMAIL (42 entries)
--  (unstructured — emails are conversational, no urgency field unless
--   the sender explicitly states priority in the subject/body)
-- ═══════════════════════════════════════════

INSERT INTO feedback (source, author, content, urgency, created_at) VALUES

-- Email: Enterprise compliance blockers (these tend to state priority explicitly)
('email', 'cto@fintech-startup.com', 'Subject: URGENT — SOC2 audit gap for Workers AI\n\nHi Cloudflare team,\n\nWe''re 3 weeks out from our SOC2 Type II audit and Workers AI data handling is the last open item. Specifically we need to know: where is inference data processed geographically? Is input retained after inference? Is any data used for retraining? Our auditor is asking and I have nothing to show them.\n\nThis is blocking a $4M deal so any guidance appreciated ASAP.\n\nThanks,\nMarcus', 'critical', '2026-03-09 07:00:00'),
('email', 'legal@healthcare-app.io', 'Subject: BAA requirement for Workers AI — product launch blocker\n\nHello,\n\nOur HIPAA compliance officer flagged that we need a Business Associate Agreement specifically covering Workers AI before we can process any patient data through AI inference endpoints. We looked through the trust center and legal pages but couldn''t find one.\n\nDoes Cloudflare offer BAAs that cover Workers AI data flows? This is genuinely blocking our launch which was supposed to be next week.\n\nBest regards,\nDr. Sarah Chen\nChief Legal Officer', 'critical', '2026-03-05 08:00:00'),
('email', 'ciso@insurance-corp.com', 'Subject: Workers AI audit log requirements — regulatory compliance\n\nTeam,\n\nFor financial services regulation we must demonstrate full AI usage traceability. We need audit logs showing: which models were called, input/output token counts, and requesting Worker ID. Currently the logging shows absolutely none of this. Our compliance deadline is end of quarter.\n\nPlease advise on timeline for this capability.\n\nRegards,\nJames Morrison, CISO', 'critical', '2026-03-03 09:00:00'),
('email', 'dpo@eu-saas-company.de', 'Subject: GDPR Art. 28 — DPA gap for Workers AI\n\nHallo,\n\nUnder GDPR Article 28 we require a Data Processing Agreement specifically addressing Workers AI. The current Cloudflare DPA covers CDN and DNS but says nothing about AI inference, model hosting, or data retention for AI inputs/outputs. Our legal team will not approve production deployment without this.\n\nCan you point us to the right document or contact?\n\nMit freundlichen Grüßen,\nKlaus Weber\nData Protection Officer', NULL, '2026-02-26 08:00:00'),

-- Email: Product feedback (mostly no urgency — just people writing in)
('email', 'pm@enterprise-saas.com', 'Subject: Data residency guarantees for EU — needed for Workers adoption\n\nHi there,\n\nWe want to adopt Workers globally but our EU customers need data residency guarantees. The D1 "location hint" is not sufficient for GDPR compliance — a hint isn''t a contractual guarantee. We need a binding legal commitment that EU data stays in EU. Without this we can''t move forward unfortunately.\n\nHappy to jump on a call to discuss.\n\nBest,\nAmanda', NULL, '2026-03-07 09:00:00'),
('email', 'lead@mobile-app.io', 'Subject: Workers AI image classification broken on rotated images\n\nHey,\n\nSo we ran a test with 500 production photos and Workers AI ResNet accuracy drops from 94% to 61% on rotated images. Like, a cat rotated 90 degrees gets classified as a bookshelf lol. Seems like it just needs an EXIF auto-rotation preprocessing step before inference.\n\nIs this on your roadmap? It''s kind of a dealbreaker for our photo feature.\n\nCheers,\nRaj', NULL, '2026-03-06 16:00:00'),
('email', 'founder@ai-startup.com', 'Subject: Feature request — persistent system prompts for Workers AI\n\nHi Cloudflare,\n\nQuick one — every API call to Workers AI includes our 2000-token system prompt which wastes like 60% of our inference budget on repeated context. OpenAI has cached system prompts which solves this. Even a basic prompt caching mechanism would cut our AI costs in half.\n\nWould love to know if this is being considered.\n\nThanks!\nLisa', NULL, '2026-03-02 15:00:00'),
('email', 'vp_eng@marketplace.com', 'Subject: D1 full-text search support?\n\nHi,\n\nWe have 500K product descriptions in D1 and need to search across them. Right now we''re fetching all rows into Worker memory and searching there which is... not great. Hits memory limits, slow, the whole deal. Native FTS5 support would solve this instantly. Is it planned?\n\nThanks,\nDavid Park\nVP Engineering', NULL, '2026-02-28 10:00:00'),
('email', 'cto@realtime-saas.com', 'Subject: Durable Objects hibernation docs are a mess\n\nHey team,\n\nI''ve spent a full day trying to implement websocket hibernation and the documentation is scattered across three blog posts and two docs pages that contradict each other. One says use webSocketMessage() the other says handleWebSocketMessage(). Which one is it?? Please just give us one canonical reference page.\n\nFrustrated but still a fan,\nOmar', NULL, '2026-02-24 14:00:00'),
('email', 'architect@video-platform.com', 'Subject: R2 upload failures on large files\n\nHello,\n\nWe upload video files (2-10GB) to R2 via streaming multipart and they frequently fail at 70-90% completion with "RequestTimeout". The thing is our upload stream is still actively sending data when the timeout hits. Something on the server side is killing the connection even though we''re still uploading.\n\nThis is happening multiple times a day and our users are complaining.\n\nBest,\nTina Walsh', NULL, '2026-02-22 11:00:00'),
('email', 'lead@fintech-api.com', 'Subject: Exactly-once delivery for Workers Queue — critical for payments\n\nHi,\n\nWorkers Queue gives us at-least-once delivery but we need exactly-once for financial transactions. The docs mention idempotency in passing but provide zero patterns or helpers. We basically need something like AWS SQS FIFO deduplication. Without it we''re seeing duplicate payment processing in edge cases.\n\nThis is pretty urgent for us — any timeline on exactly-once support?\n\nRegards,\nMike Chen', NULL, '2026-02-20 08:00:00'),
('email', 'eng_mgr@social-app.com', 'Subject: R2 race condition on concurrent uploads\n\nHey,\n\nFound a fun one — when two users upload to the same R2 key simultaneously, one silently overwrites the other. No conflict detection, no error, nothing. We need conditional put with ETag matching like S3 has.\n\nKind of surprised this isn''t already a thing tbh.\n\nThanks,\nJen', NULL, '2026-02-18 13:00:00'),

-- Email: DX feedback (casual emails, no urgency)
('email', 'dev@agency.co', 'Subject: Pages vs Workers confusion — cost us 2 days\n\nSo we deployed 3 client projects to Pages thinking it supports Worker bindings... turns out the config syntax and binding model are completely different. A simple comparison page saying "use Workers when X, use Pages when Y" would have saved us 2 full days.\n\nJust wanted to flag this as a DX issue. Love the platform otherwise.\n\n- Alex', NULL, '2026-03-08 12:00:00'),
('email', 'architect@media-co.com', 'Subject: R2 multipart upload chunk size guidance\n\nHi,\n\nWe tested R2 multipart uploads with 5MB, 50MB, and 100MB chunks for files >5GB and got a 3x performance difference between the worst and best config. This should really be documented somewhere with benchmarks. We had to figure it out through trial and error.\n\nBest,\nRachel', NULL, '2026-03-05 14:00:00'),
('email', 'infra@logistics-saas.com', 'Subject: D1 sessions documentation is misleading\n\nHey there,\n\nThe D1 read replicas docs mention "sessions" but never explain when to use them vs direct reads. We implemented sessions everywhere and latency increased 40% because it turns out sessions add a coordination round-trip that we didn''t need. Took us a while to figure out we were doing it wrong.\n\nA decision guide would be really helpful here.\n\nThanks,\nPriya', NULL, '2026-03-04 10:00:00'),
('email', 'intern@tech-company.com', 'Subject: Feedback from a CS student\n\nHi!\n\nI''m a computer science student using Cloudflare Workers for a school project. The Getting Started guide throws around terms like "bindings", "durable objects", and "service workers" without ever defining them. I spent most of my first day just googling terminology lol. A glossary page or a beginner-specific tutorial would help so much.\n\nThanks for the free tier btw — its amazing for students!\n\nBest,\nJordan', NULL, '2026-03-03 11:00:00'),
('email', 'devrel@partner-co.com', 'Subject: Idea — community knowledge base from Discord\n\nHey Cloudflare team,\n\nRandom thought — the developer Discord is super active and helpful but its completely unsearchable for anyone who joins later. Great answers to common questions are buried in 6-month-old threads. What if you indexed Discord Q&As into a searchable community KB? Would save your support team time too I bet.\n\nJust a suggestion, no urgency.\n\nCheers,\nNat', NULL, '2026-02-28 09:00:00'),
('email', 'ops@ecommerce-brand.com', 'Subject: Vercel to Workers migration story + feedback\n\nHi,\n\nJust finished migrating our checkout flow from Vercel Edge to Workers. Good news: conversion improved 3x due to latency reduction! Bad news: the migration itself took 2 weeks because there''s no Vercel-to-Cloudflare guide anywhere. The binding model is fundamentally different from env vars and figuring that out was painful.\n\nWould happily help contribute to a migration guide if you''re interested.\n\nBest,\nSteve', NULL, '2026-02-26 13:00:00'),
('email', 'tech_writer@docs-agency.com', 'Subject: Docs inconsistency — wrangler.toml vs wrangler.jsonc\n\nHi,\n\nI''m reviewing CF docs for a client migration guide and noticed the Workers docs reference wrangler.toml in some places and wrangler.jsonc in others. Code examples mix both formats randomly. This is confusing for newcomers. My recommendation: pick one as the primary format and mention the alternative in a footnote.\n\nHappy to provide more detailed feedback if helpful.\n\nRegards,\nEmily Torres', NULL, '2026-02-24 10:00:00'),
('email', 'team_lead@startup-x.com', 'Subject: Onboarding gap — environment variables\n\nHey,\n\nWe onboarded 4 developers this month and literally every single one asked the same question: "where do I put environment variables?" The answer is wrangler secret put or vars in wrangler.toml but neither is mentioned in the quickstart. People only discover it by accident or by asking in Discord.\n\nSmall fix, big impact.\n\nThanks,\nPat', NULL, '2026-02-22 09:00:00'),
('email', 'platform_eng@mid-size.com', 'Subject: Service Bindings docs need serious expansion\n\nHi,\n\nWe need Worker-to-Worker communication without HTTP overhead. Service Bindings exist which is great but the docs are literally a single page with one basic example. How do we share types between workers? Error handling across bindings? Request tracing? None of this is covered.\n\nWe basically had to reverse-engineer everything from the source code.\n\nBest,\nCarlos', NULL, '2026-02-20 14:00:00'),
('email', 'sre@monitoring-co.com', 'Subject: Logpush delay too high for incident response\n\nTeam,\n\nWorkers Logpush delivers with 5-15 minute delay which is way too slow for incident response. The wrangler tail alternative disconnects every few minutes making it useless too. We need either faster Logpush or a reliable long-lived tail connection. Currently we''re flying blind during incidents.\n\nThanks,\nDan', NULL, '2026-02-18 11:00:00'),
('email', 'backend@gaming-studio.com', 'Subject: Durable Objects alarm timing precision\n\nHi there,\n\nQuick question — the DO alarm API has a minimum interval of 1 second but we''re seeing +/- 500ms jitter in practice. For game tick synchronization we really need sub-100ms precision. Is there any way to get tighter timing guarantees? Or is this a fundamental limitation?\n\nThanks,\nMike', NULL, '2026-02-16 15:00:00'),
('email', 'api_lead@b2b-platform.com', 'Subject: 1MB response size limit forcing unnecessary pagination\n\nHello,\n\nThe 1MB response size limit for non-streaming responses is forcing us to paginate every single API endpoint. Our dashboard aggregation returns 1.2MB of JSON which is barely over. Streaming JSON is complex and breaks half the HTTP client libraries our customers use. Could you bump it to 5MB? Would solve the problem for 99% of use cases.\n\nRegards,\nAnna', NULL, '2026-02-14 10:00:00'),

-- Email: Pricing / casual (very informal, no urgency)
('email', 'solo@indie-dev.com', 'Subject: pricing suggestion\n\nhey! love the free tier for side projects but the jump to $5/mo is steep for my little weekend project that gets like 150k req/day. any chance of a $2 hobby tier with 500k daily? would capture every indie dev who outgrew free but doesnt need enterprise stuff.\n\njust a thought, keep up the great work\n\n— sam', NULL, '2026-03-06 06:00:00'),
('email', 'teacher@cs-department.edu', 'Subject: Student plan availability in Canada\n\nHello,\n\nI teach cloud computing at the University of British Columbia and would love to have my students use Workers. The student plan is great but it''s only for US .edu emails. Our university uses .ca domains. Can you expand the program internationally? Happy to be a beta tester.\n\nThanks,\nProf. Michelle Lapointe', NULL, '2026-03-04 08:00:00'),
('email', 'blogger@tech-blog.com', 'Subject: D1 storage limits for a comparison article\n\nHi,\n\nWriting a serverless database comparison and D1 pricing is straightforward but I cannot find a clear answer on max storage per database. Docs say "billed per GB" but never state a maximum. AWS RDS clearly states limits. Is there a max? Would help me give accurate info to readers.\n\nThanks,\nJake', NULL, '2026-03-01 12:00:00'),
('email', 'consultant@cloud-advisory.com', 'Subject: Workers value prop page needed\n\nHi Cloudflare team,\n\nI consult for mid-size companies and the #1 question I get is "why Workers over Lambda or Cloud Run?" The CF marketing site focuses on CDN/security which doesn''t help. The developer platform needs its own value prop page with benchmarks, pricing comparisons, and migration paths. Right now I make my own comparison slides every time which isn''t ideal.\n\nHappy to share what I''ve put together if you want.\n\nBest,\nRobert Kim', NULL, '2026-02-27 14:00:00'),

-- Email: Praise (super casual, no urgency obviously)
('email', 'cto@fast-growing-startup.com', 'Subject: Just wanted to say thanks\n\nHey Cloudflare team,\n\nNo ask here, just wanted to say thank you. We migrated from a $3000/mo AWS setup to Workers + D1 + R2 for $47/month. Same traffic, better performance, zero ops. Your platform lets our 3-person eng team punch way above our weight.\n\nSeriously, thank you.\n\n— Rita', NULL, '2026-03-08 16:00:00'),
('email', 'eng_vp@profitable-saas.com', 'Subject: Workers appreciation\n\nHi,\n\nJust wanted to share — Workers has been our secret weapon for 18 months now. Zero downtime, zero scaling incidents, zero infra management. Our 12-person backend team spends 100% of their time on product logic instead of fighting AWS configs. Keep doing what you''re doing.\n\nBest,\nChris Miller\nVP Engineering', NULL, '2026-03-02 17:00:00'),
('email', 'founder@bootstrapped.io', 'Subject: D1 convert here\n\nhey,\n\njust wanted to say d1 is the first serverless database that actually feels like a real database to me. sql, transactions, indexing, it just works. tried planetscale, neon, turso — d1 is where we ended up. wrangler migration cli is super underrated btw.\n\nkeep it up!\n\n— tony', NULL, '2026-02-25 10:00:00'),
('email', 'devops@scale-startup.com', 'Subject: Workers Analytics Engine is a hidden gem\n\nHey,\n\nNot sure if your team knows this but Workers Analytics Engine is incredibly underappreciated. We replaced our entire Mixpanel setup with custom analytics on AE + Workers. 100x cheaper, we own our data, and the SQL API is great. You should market this more honestly.\n\nCheers,\nLiam', NULL, '2026-02-19 09:00:00');


-- ═══════════════════════════════════════════
--  COMMUNITY FORUM (42 entries)
--  (semi-structured — forum posts vary wildly in quality and format)
-- ═══════════════════════════════════════════

INSERT INTO feedback (source, author, content, urgency, created_at) VALUES

-- Forum: Technical issues / bugs
('forum', 'CloudNewbie42', 'Help needed — D1 + KV bindings together?\n\nSo I''m trying to set up a Worker with both D1 and KV. The wrangler.toml docs show each binding separately but never both together. When I add both I get "configuration error" — no detail about WHICH binding is wrong. Spent 2 hours on trial and error before figuring it out. Am I the only one with this issue?\n\nEDIT: fixed it, there was a trailing comma. But the error message is terrible.', NULL, '2026-03-09 10:30:00'),
('forum', 'DBExpert_Tom', 'D1 performance cliff at 100K rows\n\nHas anyone else noticed D1 queries getting dramatically slower after ~100K rows? Simple SELECT by indexed column goes from 2ms to 200ms. EXPLAIN shows index is being used. My theory is the internal page cache is too small for larger tables but I can''t find any tuning options. Is this just a D1 limitation?', NULL, '2026-03-08 14:00:00'),
('forum', 'AIBuilder_Priya', 'Workers AI returning malformed JSON ~15% of the time\n\nWe''re using Llama 3.1 for structured output and it returns broken JSON about 15% of the time. Missing closing braces, random text after the JSON, markdown code blocks wrapping the JSON. We have "respond ONLY with valid JSON" in the prompt and it still does it. Anyone found a reliable workaround? Thinking about adding a retry loop but that seems janky.', NULL, '2026-03-07 16:00:00'),
('forum', 'SecurityGuru_Alex', 'D1 database access control — security concern\n\nIs there any way to restrict D1 database access to specific Workers? Currently ANY Worker in the account can access ANY D1 database just by knowing the name. For multi-team orgs this is a huge security risk. We need database-level ACLs or at minimum binding-level restrictions. Am I missing something or does this not exist?', NULL, '2026-03-06 09:30:00'),
('forum', 'CronDebugger', 'Cron Worker silently missing executions\n\nMy cron Worker runs every 5 minutes and has missed 3 executions this week. No error in logs, no failed execution recorded, the cron just... didn''t fire. Is there a reliability SLA for Cron Triggers? Starting to question whether we can trust this for production workloads.', NULL, '2026-03-05 07:00:00'),
('forum', 'KV_Puzzled', 'KV read-after-write consistency broken?\n\nKV .put() returns success but .get() returns null for 2-3 seconds after. I know docs say "eventually consistent" but within the SAME Worker request shouldn''t it be read-after-write consistent? This is breaking our session management. Feels like a bug not a feature tbh.', NULL, '2026-03-04 13:00:00'),
('forum', 'WranglerWoes', 'WARNING: wrangler dev --remote uses production database\n\nJust learned the hard way that wrangler dev --remote connects to your PRODUCTION D1 database. I accidentally ran a DELETE query against prod data while developing. There really should be a confirmation prompt or warning when using --remote with destructive operations. Posting this so nobody else makes the same mistake.', NULL, '2026-03-03 11:00:00'),
('forum', 'QueueConsumer', 'Workers Queue silently discards failed messages — lost 500 payment events\n\nPSA: Workers Queue retries failed messages 3 times then discards them PERMANENTLY. No dead letter queue, no way to inspect failed messages, no retry count exposed to consumer. We lost 500 payment events before discovering this behavior. This needs to be documented much more prominently.', NULL, '2026-03-01 08:00:00'),
('forum', 'TypeScriptPain', 'D1 TypeScript types are useless — everything is Record<string, unknown>\n\nEvery D1 query result is typed as Record<string, unknown>. Casting everywhere defeats the entire purpose of TypeScript. Drizzle ORM helps but adds 40KB to the bundle which feels wrong for a lightweight Worker. Are there plans for native typed query results?', NULL, '2026-02-28 14:00:00'),
('forum', 'MemoryWatcher', 'Worker memory usage doesn''t match dashboard numbers\n\nDashboard says my Worker uses 15MB but it crashes with OOM when handling what should be ~50MB of data. The 128MB limit seems way lower in practice. Does anyone know how memory is actually measured? Is V8 overhead included in the limit?', NULL, '2026-02-26 09:00:00'),

-- Forum: Architecture / best practices questions
('forum', 'ArchitectMike', 'Best pattern for async background work in Workers?\n\nWe receive webhooks and need to return 200 immediately, then process data with AI asynchronously. waitUntil() works but the docs are unclear: does it count against CPU time? What happens if processing exceeds the limit? Does the response still get sent? Would appreciate any real-world patterns people are using.', NULL, '2026-03-05 13:00:00'),
('forum', 'ScaleUpSarah', 'How to stream large JSON responses from D1?\n\nHitting the 1MB response limit aggregating dashboard data. Docs mention streaming but examples only show text/SSE streams. How do you actually stream a large JSON array from D1 query results? Couldn''t find a single example anywhere. Currently paginating client-side which is ugly.', NULL, '2026-03-04 11:00:00'),
('forum', 'MigrationMark', 'PostgreSQL to D1 migration report — pain points\n\nJust migrated from Supabase (PG) to D1 (SQLite). Performance improved which is great but migration was rough. Had to manually convert: JSONB→TEXT, SERIAL→INTEGER AUTOINCREMENT, NOW()→datetime(''now''), array columns→JSON strings. Theres probably more I''m forgetting. A pg-to-sqlite converter tool would save so many people so much time.', NULL, '2026-03-02 16:00:00'),
('forum', 'RateLimitDesigner', 'Official rate limiting pattern for Workers?\n\nSliding window with KV? Token bucket with Durable Objects? Fixed window with D1? Each has tradeoffs and there''s zero official guidance. I''ve read like 8 blog posts and they all recommend different things. A "Rate Limiting Cookbook" from Cloudflare would help everyone. What are you all using?', NULL, '2026-03-01 10:00:00'),
('forum', 'MultiTenantBuilder', 'Multi-tenancy on D1 — separate DBs or shared with tenant_id?\n\nBuilding a multi-tenant SaaS. Should each tenant get their own D1 database or use a shared one with tenant_id columns everywhere? Docs don''t mention multi-tenancy at all. This is literally the first architectural decision every SaaS dev faces and there''s no guidance. What are people doing in practice?', NULL, '2026-02-27 12:00:00'),
('forum', 'CachingStrategy', 'AI response caching patterns anyone?\n\nCaching Workers AI responses in KV by prompt hash. Problem: identical prompts with different user contexts shouldn''t share cache. Also unclear on invalidation — when a model updates, all cached responses become stale. Anyone built a good caching layer for this? Would love to see a guide.', NULL, '2026-02-25 14:00:00'),
('forum', 'AuthPatterns', 'OAuth2 in Workers — what''s the right approach?\n\nTrying to implement OAuth2 auth code flow in a Worker. Stateless nature makes it tricky because we need to store the state parameter between redirect and callback. Using KV works but feels hacky. Tried Durable Objects too but seems overkill. Is there an official pattern? What do people use?', NULL, '2026-02-23 09:00:00'),
('forum', 'FileUploadDev', 'File uploads exceeding CPU time limit\n\nrequest.formData() works for small files but a 50MB upload exceeds CPU time during parsing. Need a streaming multipart parser that doesn''t load everything into memory. Tried a few npm packages but none work in the Workers runtime. Anyone solved this?', NULL, '2026-02-21 16:00:00'),
('forum', 'ErrorHandlingPro', 'Unified error handling across D1 + Workers AI?\n\nCurrently wrapping everything in try-catch but D1 and AI bindings return errors in completely different shapes. D1 throws Error objects, AI returns error in response body. Building a wrapper around both but feels like something the platform should handle. What patterns are people using?', NULL, '2026-02-19 11:00:00'),
('forum', 'CIExpert', 'Monorepo CI/CD with Workers — how?\n\nSetting up GitHub Actions for a monorepo with 8 Workers. wrangler-action works great for a single Worker but there''s zero documentation on monorepo patterns. Each Worker needs its own wrangler.toml and deploy step. Currently doing a janky matrix strategy. Would love to see what others have built.', NULL, '2026-02-17 08:00:00'),

-- Forum: Feature discussions
('forum', 'GraphQLBuilder', 'GraphQL on Workers — what''s everyone using?\n\nAnyone running GraphQL on Workers? Apollo Server is way too heavy (2MB bundle). graphql-yoga works but there''s no docs on D1 data sources. Would love an official CF GraphQL template with D1 integration. Also a playground in the dashboard would be chef''s kiss.', NULL, '2026-03-06 15:00:00'),
('forum', 'WebSocketPro', 'WebSocket hibernation should be the default example\n\nThe non-hibernating WebSocket pattern wastes 10x CPU on idle connections. Hibernation API exists but its buried in a 2024 blog post thats not even linked from official docs. Why isn''t this the default getting started example? New devs are building the wasteful way because its what the docs show.', NULL, '2026-03-03 14:00:00'),
('forum', 'EventDriven', 'Native event bus between Workers?\n\nUsing Queue for Worker-to-Worker communication but its async only. For request-time fan-out to multiple Workers we need synchronous dispatch. Service Bindings work but you have to know target Workers at deploy time which doesn''t work for plugin architectures. Anyone found a good pattern?', NULL, '2026-02-28 10:00:00'),
('forum', 'SchedulerDev', 'Workflows documentation is severely lacking\n\nWorkflows look promising for ETL but the docs have ONE example — a simple 3-step workflow. We need docs on: error handling between steps, conditional branching, parallel execution, timeout config. These are basic workflow features that every production pipeline needs. The single example is not enough.', NULL, '2026-02-24 13:00:00'),
('forum', 'DatabaseWishlist', 'D1 wishlist after 8 months in production\n\nBeen running D1 in production for 8 months. My wishlist:\n1. RETURNING clause for INSERT/UPDATE\n2. Full-text search (FTS5)\n3. ALTER TABLE that actually works\n4. JSON functions (json_extract etc)\n5. Read replicas in more regions\n\nAny of these would be huge. All of them would make D1 truly enterprise-ready.', NULL, '2026-02-22 11:00:00'),
('forum', 'ObservabilityNerd', 'Distributed tracing for Workers — when?\n\nRequest hits Worker A → calls Worker B via Service Binding → queries D1. Zero trace ID connecting any of these. We built custom tracing but its fragile and adds overhead. Native OpenTelemetry support would be absolutely game-changing. Is this on the roadmap?', NULL, '2026-02-20 14:30:00'),

-- Forum: Positive / Success stories
('forum', 'HappyDev_Chris', 'Workers + Hono + D1 = best DX in 15 years\n\nJust wanted to share a win. Deployed a production API serving 100K req/day in a single afternoon. Global p99 under 20ms. Total cost: $5/month. I''ve been doing this for 15 years and this is the best developer experience I''ve ever had. Wrote a blog post if anyone wants the architecture details.', NULL, '2026-03-03 10:00:00'),
('forum', 'ConvertedSkeptic', 'D1 skeptic turned believer\n\nWas super skeptical about serverless databases but D1 won me over. SQL is familiar, Wrangler migrations work well, cost is 10x lower than RDS. Only wishes: better error messages and a visual query explorer in the dashboard. Otherwise genuinely impressed.', NULL, '2026-02-28 15:00:00'),
('forum', 'StartupSuccess', 'Running entire startup on CF for $12/month\n\n3-person team, Workers + D1 + R2 + Workers AI. Total infra: $12/month for 50K MAU. Cleared YC interviews partly because our burn rate is so low. Cloudflare is honestly an unfair advantage for bootstrapped startups. Happy to answer questions about our setup.', NULL, '2026-02-25 17:00:00'),
('forum', 'EnterpriseWin', 'Enterprise approval after 6 months eval\n\nOur company (2000 employees) finally approved Workers for production after 6 months of evaluation. Security team signed off on SOC2. Performance exceeded expectations. Only feedback: enterprise onboarding guide could use more detail but overall very positive experience.', NULL, '2026-02-21 09:00:00'),
('forum', 'CommunityLove', 'The Discord community is incredible\n\nJust want to give a shoutout to the Workers Discord. Asked about D1 connection pooling and got a detailed answer from an actual Cloudflare engineer within 20 minutes. The official support channels could learn from the community responsiveness tbh.', NULL, '2026-02-18 12:00:00'),
('forum', 'PerformanceWin', 'Workers vs Lambda benchmarks — edge is real\n\nRan proper benchmarks: Workers API serves p50 in 4ms, p99 in 18ms globally. Same API on Lambda + Aurora: p50 45ms, p99 320ms. Edge architecture is a genuine performance leap, not just marketing hype. Posted full methodology in the linked thread.', NULL, '2026-02-15 10:00:00');


-- ═══════════════════════════════════════════
--  ADDITIONAL ENTRIES TO REACH 250 (54 more)
-- ═══════════════════════════════════════════

INSERT INTO feedback (source, author, content, urgency, created_at) VALUES

-- Discord: additional real-world issues (9)
('discord', 'cache_confused#8812', 'Workers Cache API .put() silently ignores responses larger than 512KB. No error thrown. The cached response just never appears in cache.match(). Took us a full day to discover our product catalog responses were too large to cache.', 'high', '2026-03-09 07:45:00'),
('discord', 'env_vars_guy#2233', 'Secret environment variables set via wrangler secret put are not available during wrangler dev --local. The docs do not mention this. We had to create a .dev.vars file manually which duplicates every secret. There should be a wrangler secret pull command.', 'medium', '2026-03-08 13:30:00'),
('discord', 'durable_objects#5577', 'Durable Object alarm fires twice when the DO is evicted and recreated between alarm scheduling and execution. We process a payment on alarm so double-firing means double-charging customers. Need at-most-once delivery guarantee for alarms.', 'critical', '2026-03-07 04:00:00'),
('discord', 'monorepo_dev#4490', 'Deploying Workers from a pnpm monorepo is broken. Wrangler cannot resolve workspace dependencies. Error: "Could not resolve module @myorg/shared-utils". Works fine with npm workspaces. Pnpm is the most popular monorepo tool and this should be supported.', 'high', '2026-03-05 15:30:00'),
('discord', 'latency_hunter#6612', 'D1 queries from Workers in Asia-Pacific regions are 10x slower than from US regions. A simple SELECT by primary key takes 3ms in US but 35ms from Singapore. I thought D1 had read replicas globally? Where is the edge caching?', 'high', '2026-03-04 02:00:00'),
('discord', 'size_limit#7799', 'Workers has a 1MB script size limit after compression. Our Worker with all dependencies is 1.3MB. The error says "script too large" but does not tell you the current size or the limit. We had to tree-shake for 4 hours to get under the limit blindly.', 'high', '2026-03-02 09:00:00'),
('discord', 'happy_convert#1100', 'Converted our Fastify API to Hono on Workers in one weekend. Performance doubled and our hosting bill went from $89/month on Railway to $5/month. The Hono middleware ecosystem is surprisingly mature. Loving this stack.', 'low', '2026-03-01 20:00:00'),
('discord', 'ai_prompt_eng#3345', 'Workers AI llama-3.1 max_tokens parameter is ignored for values over 256. Setting max_tokens to 1000 still cuts off at ~250 tokens. The docs say the model supports 8192 context but the actual generation limit is undocumented.', 'high', '2026-02-27 11:00:00'),
('discord', 'streaming_issue#8866', 'Workers AI streaming responses work in wrangler dev but return a single chunk in production. The SSE stream sends one event with the complete response instead of token-by-token. Makes our chat UI feel like a loading spinner instead of a typewriter.', 'high', '2026-02-24 16:00:00'),

-- GitHub: additional (9)
('github', 'user/bundle_analyzer', '[BUG] wrangler deploy does not report final bundle size before uploading. We exceed the 1MB compressed limit regularly and only learn after a 30-second upload attempt fails. Need a --dry-run flag or pre-upload size check with clear limit display.', 'medium', '2026-03-09 13:00:00'),
('github', 'user/sqlite_compat', '[BUG] D1 does not support SQLite JSON functions (json_extract, json_each, json_group_array). These are core SQLite 3.38+ features. Querying JSON columns requires fetching all rows and parsing in JavaScript which defeats the purpose of a SQL database.', 'high', '2026-03-08 10:00:00'),
('github', 'user/ai_embed_bug', '[BUG] Workers AI bge-small-en-v1.5 embedding model produces NaN values in output vectors when input text contains emoji characters. The NaN propagates to Vectorize similarity search and breaks all results. Workaround: strip emoji before embedding.', 'high', '2026-03-06 14:00:00'),
('github', 'user/r2_cors', '[BUG] R2 CORS configuration set via the dashboard does not apply to presigned URLs. Presigned URL responses always lack CORS headers even though the bucket has CORS rules configured. Have to proxy through a Worker which defeats the purpose of presigned URLs.', 'high', '2026-03-04 09:00:00'),
('github', 'user/workflow_state', '[BUG] Workflows lose step state when the Worker is redeployed during workflow execution. A workflow at step 3 of 5 restarts from step 1 after deploy. For long-running workflows this means hours of lost progress. Workflow state should survive deploys.', 'critical', '2026-03-02 11:00:00'),
('github', 'user/d1_import', '[FEATURE] D1 needs a bulk import command. wrangler d1 execute with a large SQL file takes 10+ minutes for 50K rows because each INSERT is a separate HTTP request. Need wrangler d1 import that batches efficiently. CSV import would be even better.', 'medium', '2026-02-28 08:00:00'),
('github', 'user/tail_filter', '[FEATURE] wrangler tail should support log-level filtering. Our Worker logs 200 lines per request at DEBUG level. Finding ERROR logs means scrolling through thousands of debug lines. Tail --level=error would make debugging 10x faster.', 'medium', '2026-02-25 10:00:00'),
('github', 'user/preview_url', '[FEATURE] Workers need preview deployment URLs like Vercel has. Every PR should get a unique URL (pr-123.my-worker.workers.dev) for QA review. Currently we deploy to a separate Worker for staging which doubles our config management.', 'medium', '2026-02-22 15:00:00'),
('github', 'user/local_d1', '[DOCS] D1 local development with wrangler dev uses a separate SQLite file from remote. There is no documentation on how to sync schema between local and remote. We manually run migrations against both which is error-prone. Need a d1 push/pull command.', 'medium', '2026-02-18 09:00:00'),

-- Support: additional (9)
('support', 'AutoScale Corp (Enterprise)', 'Workers are returning 429 rate limit errors during our Black Friday traffic spike. Our plan allows 10M requests/month and we are at 2M for the month. The rate limit seems to be per-minute not per-month but the dashboard only shows monthly totals. Need clarity on burst rate limits.', 'critical', '2026-03-09 14:00:00'),
('support', 'MultiCloud Inc (Enterprise)', 'We need to route 30% of traffic to Workers and 70% to our existing AWS backend during migration. Workers does not support percentage-based traffic splitting at the route level. We have to implement this in external DNS which adds latency and complexity.', 'high', '2026-03-07 11:30:00'),
('support', 'ComplianceFirst (Enterprise)', 'Our Workers process PCI DSS cardholder data. We need documentation confirming Workers runtime environment meets PCI DSS Level 1 requirements. The current compliance page mentions PCI for CDN but not specifically for Workers compute environment.', 'critical', '2026-03-05 07:30:00'),
('support', 'DevTeam.io (Business)', 'Wrangler login token expires after 30 days with no warning. Our CI/CD pipeline broke silently because the token expired. The deploy command returned exit code 0 with no output. Need longer-lived API tokens for CI/CD with clear expiration warnings.', 'high', '2026-03-03 08:00:00'),
('support', 'AnalyticsHub (Business)', 'Workers Analytics Engine SQL API returns inconsistent results when querying data written in the last 5 minutes. Some rows appear then disappear then reappear. The eventually consistent nature is documented but a 5-minute window is too large for real-time dashboards.', 'medium', '2026-03-01 12:00:00'),
('support', 'GovTech Solutions (Enterprise)', 'We need FedRAMP authorization for Workers to serve US government clients. The Cloudflare FedRAMP package covers CDN and WAF but not Workers compute. This blocks a $5M government contract. When will Workers be included in FedRAMP scope?', 'high', '2026-02-26 09:00:00'),
('support', 'ChatApp.io (Business)', 'Durable Objects have a 32KB limit per stored value with storage.put(). Our chat room state object is 45KB. The workaround of splitting into multiple keys adds read amplification. The 32KB limit is not prominently documented and we hit it in production.', 'high', '2026-02-23 14:00:00'),
('support', 'VideoHost (Business)', 'R2 egress is free which is amazing but we cannot find documentation on whether there is a bandwidth rate limit per bucket. We serve video files and during a viral moment traffic spiked 100x. Everything worked but we want to know if there are hidden limits.', 'medium', '2026-02-20 11:00:00'),
('support', 'RetailAPI (Business)', 'Our Worker makes 50 subrequests per invocation to different microservices. We are hitting the 50 subrequest limit consistently. The docs say 50 for free tier and 1000 for paid but we are on paid and still getting limited at 50. Is this a plan activation issue?', 'high', '2026-02-17 10:00:00'),

-- Twitter: additional (9)
('twitter', '@wasm_builder', '@CloudflareDev Workers WASM support is underrated. Ported our Rust image processing library to WASM and it runs at near-native speed. Processing 1000 images/second on the edge. The future is WASM on edge compute.', 'low', '2026-03-09 11:00:00'),
('twitter', '@ci_broken', '@CloudflareDev wrangler-action v3 silently fails when the CLOUDFLARE_API_TOKEN secret is expired. No error message. The step shows green checkmark but nothing deploys. Spent 2 hours debugging before checking token expiry. Please fail loudly.', 'high', '2026-03-07 08:00:00'),
('twitter', '@dx_reviewer', 'Rating @CloudflareDev developer experience: Getting started: 9/10. First deploy: 10/10. Adding D1: 4/10 (binding confusion). Adding AI: 6/10 (deprecated package traps). Debugging production: 3/10 (error messages). The extremes are extreme.', 'medium', '2026-03-05 17:00:00'),
('twitter', '@global_latency', 'Tested @CloudflareDev Workers response times from 50 countries. Median is 11ms. Worst case is 43ms from rural Brazil. AWS Lambda worst case from same location is 380ms. The CDN-backed compute model is genuinely global unlike region-specific clouds.', 'low', '2026-03-03 14:00:00'),
('twitter', '@ecosystem_watch', '@CloudflareDev Workers npm ecosystem hit 500+ packages this month. Hono, Drizzle, Lucia auth, and workers-rs for Rust. The ecosystem is maturing fast. Two years ago there were maybe 20 packages. The tipping point is here.', 'low', '2026-03-01 12:00:00'),
('twitter', '@database_debates', 'Controversial take: @CloudflareDev D1 should not have used SQLite. Great for simplicity but the feature gaps (no ALTER TABLE, no JSON functions, no FTS) are becoming blockers as projects grow. LibSQL or DuckDB would have been better foundations.', 'medium', '2026-02-26 18:00:00'),
('twitter', '@billing_surprise', 'PSA: @CloudflareDev Workers AI billing is based on "neurons" not tokens. 1 neuron is NOT 1 token. A Llama 3.1 8B request costs 130 neurons per 1K input tokens. This is NOT clear on the pricing page. My first bill was 3x what I expected.', 'high', '2026-02-23 09:00:00'),
('twitter', '@edge_case', '@CloudflareDev Workers cannot set response headers after res.write() starts streaming. This is a standard HTTP limitation but the error message is "Headers already sent" with no suggestion to set headers before streaming begins. Confusing for newcomers.', 'medium', '2026-02-19 15:00:00'),
('twitter', '@community_builder', 'The @CloudflareDev Workers community grew 3x in 2025. Discord has 40K members. The Workers Launchpad program funded 200+ startups. Say what you will about the DX rough edges but the community momentum is real and accelerating.', 'low', '2026-02-14 10:00:00'),

-- Email: additional (9)
('email', 'vp_platform@unicorn-startup.com', 'We process 500M API requests/month on Workers across 15 Workers. Need consolidated billing per Worker. Currently one line item for all Workers combined. Finance team cannot allocate costs to product teams without per-Worker breakdown.', 'high', '2026-03-09 08:30:00'),
('email', 'security@pentest-firm.com', 'During our security assessment of Workers we found that console.log() output is visible in wrangler tail to anyone with account access. This means API keys or tokens accidentally logged are exposed. Need log redaction or scrubbing for sensitive patterns.', 'high', '2026-03-07 10:00:00'),
('email', 'data_eng@ml-company.com', 'Workers AI embedding model bge-small-en-v1.5 has a 512 token input limit but this is not documented. We sent 1000-token product descriptions and the model silently truncated input producing poor embeddings. Discovered after indexing 100K documents.', 'high', '2026-03-05 13:00:00'),
('email', 'devex@platform-team.com', 'We evaluated Workers for our internal developer platform. The biggest gap: no deployment approval workflow. Developers can deploy to production with a single command. We need deployment gates with approval requirements for production Workers.', 'medium', '2026-03-03 14:00:00'),
('email', 'pm@content-platform.com', 'Workers AI summarization works well for English text but produces nonsensical output for multilingual content. We process customer reviews in 12 languages. Need either multilingual models or clear documentation on which models support which languages.', 'medium', '2026-03-01 11:00:00'),
('email', 'architect@banking-app.com', 'D1 transactions do not support SAVEPOINT for nested transactions. Our payment processing logic needs partial rollback capability. Without savepoints we have to restructure our entire transaction handling. PostgreSQL and even SQLite 3.6+ support this.', 'high', '2026-02-27 09:00:00'),
('email', 'sre@monitoring-saas.com', 'Workers health checks are binary: the Worker either responds or does not. We need custom health check endpoints that verify D1 connectivity, KV availability, and AI model responsiveness. A /health endpoint convention with binding status would help.', 'medium', '2026-02-24 10:00:00'),
('email', 'ceo@edge-analytics.com', 'Workers Analytics Engine is amazing but the 90-day data retention limit is a dealbreaker for our product. We need 12-month retention minimum for compliance. Would happily pay for extended retention. Currently exporting to BigQuery monthly as a workaround.', 'medium', '2026-02-21 15:00:00'),
('email', 'developer@nonprofit.org', 'We are a nonprofit using Workers for our donation platform. The $5/month paid plan is fine but you should consider a nonprofit tier with extended free limits similar to what GitHub and Vercel offer. Would help small organizations doing important work.', 'low', '2026-02-17 08:00:00'),

-- Forum: additional (9)
('forum', 'EdgeCacheExpert', 'Workers Cache API behavior is inconsistent across regions. A cached response available in US-East is not available in EU-West for up to 60 seconds. The docs say cache is per-colo but do not explain cross-colo cache propagation timing.', 'medium', '2026-03-09 12:00:00'),
('forum', 'MicroserviceArch', 'Service Bindings between Workers add 2-5ms per hop. For a request that chains 4 Workers the overhead is 8-20ms. Is this expected? Direct fetch to the Worker URL adds only 1ms. Service Bindings should be faster than HTTP not slower.', 'high', '2026-03-07 14:00:00'),
('forum', 'DataMigrator', 'Migrating 2M rows from PostgreSQL to D1. The wrangler d1 execute command processes 1 INSERT per second when reading from a SQL file. At this rate migration takes 23 days. Need bulk import capability. Even MySQL has LOAD DATA INFILE.', 'high', '2026-03-05 08:00:00'),
('forum', 'E2ETester', 'How do you end-to-end test a Worker that uses D1 + KV + AI bindings? Miniflare handles D1 and KV but there is no mock for Workers AI. Our test suite calls the real AI API which is slow, non-deterministic, and costs money. Need AI binding mock.', 'medium', '2026-03-03 16:00:00'),
('forum', 'ProdDebugger', 'Workers error "Exceeded the limit of 6 simultaneous requests" during a traffic spike. The 6-concurrent-subrequest limit is not in the main docs. Found it in a footnote on the limits page. This limit should be prominently documented with the subrequest section.', 'high', '2026-03-01 07:00:00'),
('forum', 'R2Migration', 'Migrating 500GB from S3 to R2. The S3-compatible API works but there is no migration tool or bulk copy command. We wrote a custom Worker to copy objects one by one. A wrangler r2 import-from-s3 command would save every S3 migrator days of work.', 'medium', '2026-02-26 11:00:00'),
('forum', 'VersioningDev', 'Workers do not support canary deployments natively. We want to send 5% of traffic to a new version and 95% to the current version. Cloudflare Spectrum does this for TCP but Workers has no built-in traffic splitting. Have to implement at DNS level.', 'medium', '2026-02-23 13:00:00'),
('forum', 'i18nBuilder', 'Building a multilingual app on Workers. The Accept-Language header parsing is manual. A built-in locale detection helper like Vercel has (req.geo, req.locale) would save every international app from writing the same 30 lines of language negotiation code.', 'medium', '2026-02-20 09:00:00'),
('forum', 'FirstDeploy_Lee', 'Finally got my first Worker deployed after 3 days of learning. The hardest part was not the code but understanding the wrangler.toml configuration. Once I understood bindings everything clicked. Suggestion: a visual wrangler.toml builder in the dashboard.', 'low', '2026-02-16 18:00:00');
